import socket
import threading
import select

LOCAL_PORT = {port}
REMOTE_HOST = '{host}'
REMOTE_PORT = {remote_port}

def relay(src, dst):
    try:
        while True:
            r, _, _ = select.select([src], [], [], 30)
            if r:
                data = src.recv(8192)
                if not data:
                    break
                dst.sendall(data)
    except:
        pass
    src.close()
    dst.close()

def handle(client, addr):
    try:
        remote = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        remote.connect((REMOTE_HOST, REMOTE_PORT))
        print(f'  {addr} -> {REMOTE_HOST}:{REMOTE_PORT}')
        threading.Thread(target=relay, args=(client, remote), daemon=True).start()
        relay(remote, client)
    except Exception as e:
        print(f'  Failed: {e}')
        client.close()

srv = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
srv.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
srv.bind(('0.0.0.0', LOCAL_PORT))
srv.listen(10)
print(f'Port forward: 0.0.0.0:{LOCAL_PORT} -> {REMOTE_HOST}:{REMOTE_PORT}')
try:
    while True:
        c, a = srv.accept()
        threading.Thread(target=handle, args=(c, a), daemon=True).start()
except KeyboardInterrupt:
    srv.close()

