    interfaces = []
    try:
        result = subprocess.run(['ip', '-j', 'addr'], capture_output=True, text=True, timeout=5)
        data = json.loads(result.stdout)
        for iface in data:
            for addr_info in iface.get('addr_info', []):
                if addr_info.get('family') == 'inet':
                    interfaces.append({
                        'name': iface['ifname'],
                        'ip': addr_info['local'],
                        'prefix': addr_info['prefixlen'],
                        'network': str(ipaddress.ip_network(f"{addr_info['local']}/{addr_info['prefixlen']}", strict=False))
                    })
    except (FileNotFoundError, json.JSONDecodeError, subprocess.TimeoutExpired):
        # Fallback: parse /proc/net/fib_trie or use socket
        hostname = socket.gethostname()
        try:
            ip = socket.gethostbyname(hostname)
            interfaces.append({'name': 'auto', 'ip': ip, 'prefix': 24, 'network': f'{ip}/24'})
        except:
            pass
    return interfaces

def get_arp_table():
    """Get ARP table for known hosts"""
    hosts = []
    try:
        with open('/proc/net/arp', 'r') as f:
            for line in f.readlines()[1:]:
                parts = line.split()
                if len(parts) >= 4 and parts[2] != '0x0':
                    hosts.append({'ip': parts[0], 'mac': parts[3], 'device': parts[5]})
    except FileNotFoundError:
        pass
    return hosts

def get_routing_table():
    """Get routing table"""
    routes = []
    try:
        result = subprocess.run(['ip', '-j', 'route'], capture_output=True, text=True, timeout=5)
        routes = json.loads(result.stdout)
    except:
        pass
    return routes

