    """Parse /proc/net/tcp for established connections"""
    connections = []
    try:
        with open('/proc/net/tcp', 'r') as f:
            for line in f.readlines()[1:]:
                parts = line.split()
                state = int(parts[3], 16)
                if state == 1:  # ESTABLISHED
                    local = parts[1].split(':')
                    remote = parts[2].split(':')
                    local_ip = socket.inet_ntoa(bytes.fromhex(local[0])[::-1])
                    local_port = int(local[1], 16)
                    remote_ip = socket.inet_ntoa(bytes.fromhex(remote[0])[::-1])
                    remote_port = int(remote[1], 16)
                    connections.append({
                        'local': f'{local_ip}:{local_port}',
                        'remote': f'{remote_ip}:{remote_port}'
